        import random; random.seed(0)
        scale = 0.01
        self.W_in  = [[random.gauss(0,scale) for _ in range(emb_dim)] for _ in range(vocab_size)]
        self.W_out = [[random.gauss(0,scale) for _ in range(vocab_size)] for _ in range(emb_dim)]
